# EVOLVE-BLOCK-START

def compute_model_placement(gpu_num, models):
    n = len(models)
    rates = [m.req_rate / m.slo for m in models]
    sizes = [m.model_size for m in models]

    def try_target(T):
        """Try to pack all models with max KVPR <= T using FFD bin packing.
        Effective weight of model i: rates[i] + T * sizes[i], bin capacity: T * GPU_MEM_SIZE."""
        cap = T * GPU_MEM_SIZE
        weights = [rates[i] + T * sizes[i] for i in range(n)]
        # Sort by weight descending (FFD)
        order = sorted(range(n), key=lambda i: weights[i], reverse=True)
        bins = [0.0] * gpu_num
        mem_used = [0.0] * gpu_num
        assign = [0] * n
        for idx in order:
            w = weights[idx]
            s = sizes[idx]
            # Best fit: find bin with most remaining capacity that still fits
            best_g = -1
            best_remaining = float('inf')
            for g in range(gpu_num):
                if bins[g] + w <= cap + 1e-12 and mem_used[g] + s <= GPU_MEM_SIZE - 1e-12:
                    remaining = cap - bins[g] - w
                    if remaining < best_remaining:
                        best_remaining = remaining
                        best_g = g
            if best_g == -1:
                return None  # infeasible
            assign[idx] = best_g
            bins[best_g] += w
            mem_used[best_g] += s
        return assign

    def build_state(assign):
        rem = [GPU_MEM_SIZE] * gpu_num
        wr = [0.0] * gpu_num
        for i in range(n):
            g = assign[i]
            rem[g] -= sizes[i]
            wr[g] += rates[i]
        return rem, wr

    def get_max(rem, wr):
        mx = 0.0
        for g in range(gpu_num):
            if rem[g] > 0:
                v = wr[g] / rem[g]
                if v > mx:
                    mx = v
        return mx

    def local_search(assign, rem, wr):
        improved = True
        while improved:
            improved = False
            cur_max = get_max(rem, wr)
            worst_g = 0
            for g in range(1, gpu_num):
                if rem[g] > 0 and wr[g] / rem[g] > wr[worst_g] / rem[worst_g]:
                    worst_g = g

            # Try moves from worst GPU
            for i in range(n):
                if assign[i] != worst_g:
                    continue
                si, ri = sizes[i], rates[i]
                nwr_w = wr[worst_g] - ri
                nrem_w = rem[worst_g] + si
                for g in range(gpu_num):
                    if g == worst_g:
                        continue
                    nr = rem[g] - si
                    if nr <= 0:
                        continue
                    candidate = max(nwr_w / nrem_w, (wr[g] + ri) / nr)
                    if candidate >= cur_max:
                        continue
                    # Check others
                    for g2 in range(gpu_num):
                        if g2 == worst_g or g2 == g:
                            continue
                        if rem[g2] > 0:
                            v = wr[g2] / rem[g2]
                            if v > candidate:
                                candidate = v
                    if candidate < cur_max:
                        assign[i] = g
                        wr[worst_g] -= ri
                        rem[worst_g] += si
                        wr[g] += ri
                        rem[g] -= si
                        improved = True
                        break
                if improved:
                    break

            if improved:
                continue

            # Try swaps from worst
            for i in range(n):
                if assign[i] != worst_g:
                    continue
                si, ri = sizes[i], rates[i]
                found = False
                for j in range(n):
                    if assign[j] == worst_g:
                        continue
                    g2 = assign[j]
                    sj, rj = sizes[j], rates[j]
                    nrw = rem[worst_g] + si - sj
                    nrg = rem[g2] + sj - si
                    if nrw <= 0 or nrg <= 0:
                        continue
                    candidate = max((wr[worst_g] - ri + rj) / nrw, (wr[g2] - rj + ri) / nrg)
                    if candidate >= cur_max:
                        continue
                    for g3 in range(gpu_num):
                        if g3 == worst_g or g3 == g2:
                            continue
                        if rem[g3] > 0:
