def compute_model_placement(gpu_num, models):
    n = len(models)
    rates = [m.req_rate / m.slo for m in models]
    sizes = [m.model_size for m in models]

    def build_state(assign):
        rem = [GPU_MEM_SIZE] * gpu_num
        wr = [0.0] * gpu_num
        for i in range(n):
            rem[assign[i]] -= sizes[i]
            wr[assign[i]] += rates[i]
        return rem, wr

    def get_max_kvpr(rem, wr):
        mx = 0.0
        for g in range(gpu_num):
            if rem[g] > 0 and wr[g] / rem[g] > mx:
                mx = wr[g] / rem[g]
        return mx

    def local_search(assign, rem, wr):
        while True:
            cur_max = get_max_kvpr(rem, wr)
            best_new_max = cur_max
            best_action = None

            # Try all single moves
            for i in range(n):
                gi = assign[i]
                si, ri = sizes[i], rates[i]
                kvpr_src = (wr[gi] - ri) / (rem[gi] + si)
                for g in range(gpu_num):
                    if g == gi:
                        continue
                    nr = rem[g] - si
                    if nr <= 0:
                        continue
                    kvpr_dst = (wr[g] + ri) / nr
                    cand = max(kvpr_src, kvpr_dst)
                    if cand >= best_new_max:
                        continue
                    # Check other GPUs
                    for g2 in range(gpu_num):
                        if g2 == gi or g2 == g:
                            continue
                        if rem[g2] > 0:
                            v = wr[g2] / rem[g2]
                            if v > cand:
                                cand = v
                                if cand >= best_new_max:
                                    break
                    if cand < best_new_max:
                        best_new_max = cand
                        best_action = ('m', i, g)

            # Try all swaps
            for i in range(n):
                gi = assign[i]
                si, ri = sizes[i], rates[i]
                for j in range(i + 1, n):
                    gj = assign[j]
                    if gj == gi:
                        continue
                    sj, rj = sizes[j], rates[j]
                    nri = rem[gi] + si - sj
                    nrj = rem[gj] + sj - si
                    if nri <= 0 or nrj <= 0:
                        continue
                    cand = max((wr[gi] - ri + rj) / nri, (wr[gj] - rj + ri) / nrj)
                    if cand >= best_new_max:
                        continue
                    for g2 in range(gpu_num):
                        if g2 == gi or g2 == gj:
                            continue
                        if rem[g2] > 0:
                            v = wr[g2] / rem[g2]
                            if v > cand:
                                cand = v
                                if cand >= best_new_max:
                                    break
                    if cand < best_new_max:
                        best_new_max = cand
                        best_action = ('s', i, j)

            if best_action is None:
                break
            if best_action[0] == 'm':
                _, i, g = best_action
                gi = assign[i]
                wr[gi] -= rates[i]; rem[gi] += sizes[i]
                wr[g] += rates[i]; rem[g] -= sizes[i]
                assign[i] = g
            else:
                _, i, j = best_action
                gi, gj = assign[i], assign[j]
                wr[gi] += rates[j] - rates[i]; rem[gi] += sizes[i] - sizes[j]
                wr[gj] += rates[i] - rates[j]; rem[gj] += sizes[j] - sizes[i]
                assign[i], assign[j] = gj, gi

        return assign, rem, wr, get_max_kvpr(rem, wr)

    def try_pack(T, order, mode):
        """Try bin packing at target T with given order and mode."""
        cap = T * GPU_MEM_SIZE
        weights = [rates[i] + T * sizes[i] for i in range(n)]
        bins = [0.0] * gpu_num
        mem = [0.0] * gpu_num
        assign = [0] * n
        for idx in order:
            w, s = weights[idx], sizes[idx]
            best_g = -1
            if mode == 0:  # best fit
                best_v = float('inf')
                for g in range(gpu_num):
                    if bins[g] + w <= cap + 1e-12 and mem[g] + s < GPU_MEM_SIZE:
                        v = cap - bins[g] - w
                        if v < best_v:
                            best_v = v; best_g = g
            elif mode == 1:  # worst fit
                best_v = -1.0
                for g in range(gpu_num):
                    if bins[g] + w <= cap + 1e-12 and mem[g] + s < GPU_MEM_SIZE:
                        v = cap - bins[g] - w
                        if v > best_v:
                            best_v = v; best_g = g
            else:  # first fit (by index)
                for g in range(gpu_num):
                    if bins[g] + w <= cap + 1e-12 and mem[g] + s < GPU_MEM_SIZE:
                        best_g = g; break
            if best_g == -1:
                return None
            assign[idx] = best_g
            bins[best_g] += w
            mem[best_g] += s
        return assign

    # Generate diverse sort orders
    orders = [
        sorted(range(n), key=lambda i: rates[i] + sizes[i], reverse=True),
        sorted(range(n), key=lambda i: rates[i], reverse=True),
        sorted(range(n), key=lambda i: sizes[i], reverse=True),
        sorted(range(n), key=lambda i: rates[i] / sizes[i] if sizes[i] > 0 else 0, reverse=True),
        sorted(range(n), key=lambda i: sizes[i] * rates[i], reverse=True),
    ]

    # Binary search with multiple (order, mode) combos
    candidates = []
    for order in orders:
        for mode in range(3):
            lo, hi = 0.0, 1.0
            best = None
            for _ in range(35):
                mid = (lo + hi) / 2
                r = try_pack(mid, order, mode)
                if r is not None:
                    hi = mid; best = r
                else:
                    lo = mid
            if best is not None:
                candidates.append(best)

    # Also add greedy approaches (minimize resulting KVPR per model)
    def greedy(order):
        rem = [GPU_MEM_SIZE] * gpu_num
        wr = [0.0] * gpu_num
        assign = [0] * n
        for idx in order:
            s, r = sizes[idx], rates[idx]
            best_g, best_k = -1, float('inf')
            for g in range(gpu_num):
                nr = rem[g] - s
                if nr > 0:
                    k = (wr[g] + r) / nr
                    if k < best_k:
                        best_k = k; best_g = g
            if best_g == -1:
                best_g = max(range(gpu_num), key=lambda g: rem[g])
            assign[idx] = best_g
            rem[best_g] -= s; wr[best_g] += r
        return assign

    for order in orders:
        candidates.append(greedy(order))

    # Evaluate all candidates with local search
    best_final = None
    best_score = float('inf')
    for assign in candidates:
        rem, wr = build_state(assign)
        assign, rem, wr, mx = local_search(assign, rem, wr)
        if mx < best_score:
            best_score = mx
            best_final = assign[:]

    placement = {g: [] for g in range(gpu_num)}
    for i, g in enumerate(best_final):
        placement[g].append(models[i])
    return placement

